/* ---------------------------------------------------------
   Build 3 days of 5-min interval data, values only present
   during the sun/pump run-window (06:00-18:00) each day,
   null outside it so the line breaks exactly like the
   reference screenshot.
---------------------------------------------------------- */
function buildSeries(){
  var days = ["2026-06-30","2026-07-01","2026-07-02"];
  var pv=[], pvI=[], mv=[], mi=[], mf=[], mp=[], rpm=[], temp=[];
 
  days.forEach(function(day, dIdx){
    for(var h=0; h<24; h++){
      for(var m=0; m<60; m+=15){
        var ts = new Date(day+"T"+String(h).padStart(2,"0")+":"+String(m).padStart(2,"0")+":00").getTime();
        var running = h>=6 && h<18 && !(dIdx===2 && h>=12); // day 3 stops around noon like screenshot
 
        if(running){
          var t = (h + m/60 - 6)/12; // 0..1 across the run window
          var curve = Math.sin(Math.PI*t);           // rises then falls
          var noise = (Math.random()-0.5)*6;
 
          pv.push([ts, Math.round((150*curve + 15 + noise)*10)/10]);
          pvI.push([ts, Math.round((Math.random()*0.4)*10)/10]);
          mv.push([ts, 0]);
          mi.push([ts, 0]);
          mf.push([ts, 0]);
          mp.push([ts, 0]);
          rpm.push([ts, 0]);
          temp.push([ts, Math.round((25 + t*6 + Math.random()*1.5)*10)/10]);
        } else {
          pv.push([ts, null]);
          pvI.push([ts, null]);
          mv.push([ts, null]);
          mi.push([ts, null]);
          mf.push([ts, null]);
          mp.push([ts, null]);
          rpm.push([ts, null]);
          temp.push([ts, null]);
        }
      }
    }
  });
 
  return {pv:pv, pvI:pvI, mv:mv, mi:mi, mf:mf, mp:mp, rpm:rpm, temp:temp};
}
 
var d = buildSeries();
 
var options = {
  chart:{
    height: 400,
    type: "line",
    toolbar:{ show:false },
    zoom:{ enabled:false }
  },
  series:[
    { name:"PV Voltage (V)",       data:d.pv   },
    { name:"PV Current (A)",       data:d.pvI  },
    { name:"Motor Voltage (V)",    data:d.mv   },
    { name:"Motor Current (A)",    data:d.mi   },
    { name:"Motor Frequency (Hz)", data:d.mf   },
    { name:"Motor Power (kW)",     data:d.mp   },
    { name:"Motor RPM",            data:d.rpm  },
    { name:"Temperature(°C)",      data:d.temp }
  ],
  colors:["#e53935","#1e40ff","#2e7d32","#f4a300","#e17ff0","#17c3d4","#f4a7b9","#7a1f1f"],
  stroke:{ width:2, curve:"smooth", lineCap:"round" },
  markers:{ size:0 },
  legend:{ show:false },
  dataLabels:{ enabled:false },
  grid:{ borderColor:"#eef0f3", xaxis:{ lines:{ show:false } } },
  xaxis:{
    type:"datetime",
    labels:{ style:{ fontSize:"11px", colors:"#A0ACBB" } },
    axisBorder:{ show:false },
    axisTicks:{ show:false }
  },
  yaxis:{
    min:0, max:210,
    labels:{ style:{ fontSize:"11px", colors:"#A0ACBB" } }
  },
  tooltip:{
    shared:true,
    intersect:false,
    x:{ format:"dd-MMM-yyyy HH:mm" },
    style:{ fontSize:"12px" }
  }
};
 
var chart = new ApexCharts(document.querySelector("#parameters-history-chart"), options);
chart.render();
 
/* ---------------------------------------------------------
   Bootstrap-datepicker wiring for the toolbar date boxes
---------------------------------------------------------- */
$(function(){
  $('#startDate').datepicker({
    format: 'dd/mm/yyyy',
    autoclose: true,
    todayHighlight: true,
    orientation: 'bottom auto'
  }).on('changeDate', function(e){
    // keep end date from being before the new start date
    $('#endDate').datepicker('setStartDate', e.date);
    refreshChartFromDates();
  });
 
  $('#endDate').datepicker({
    format: 'dd/mm/yyyy',
    autoclose: true,
    todayHighlight: true,
    orientation: 'bottom auto'
  }).on('changeDate', function(e){
    $('#startDate').datepicker('setEndDate', e.date);
    refreshChartFromDates();
  });
 
  // set initial bounds so start/end can't cross each other
  $('#endDate').datepicker('setStartDate', $('#startDate').datepicker('getDate'));
  $('#startDate').datepicker('setEndDate', $('#endDate').datepicker('getDate'));
});
 
function parseDMY(str){
  var p = str.split('/');
  return p[2] + '-' + p[1] + '-' + p[0]; // yyyy-mm-dd
}
 
function refreshChartFromDates(){
  var start = $('#startDate').val();
  var end   = $('#endDate').val();
  if(!start || !end) return;
 
  // Rebuild the 3-day-style dataset but anchored on the picked range.
  // (buildSeries() below still generates the run-window pattern;
  //  here we just regenerate against the same shape for the demo.
  //  Swap this for a real API call keyed on start/end when ready.)
  var fresh = buildSeries();
  chart.updateSeries([
    { data: fresh.pv },
    { data: fresh.pvI },
    { data: fresh.mv },
    { data: fresh.mi },
    { data: fresh.mf },
    { data: fresh.mp },
    { data: fresh.rpm },
    { data: fresh.temp }
  ]);
}
 
document.getElementById("refreshBtn").addEventListener("click", function(){
  var fresh = buildSeries();
  chart.updateSeries([
    { data: fresh.pv },
    { data: fresh.pvI },
    { data: fresh.mv },
    { data: fresh.mi },
    { data: fresh.mf },
    { data: fresh.mp },
    { data: fresh.rpm },
    { data: fresh.temp }
  ]);
});